1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_RATE = 0.1;
12	
13	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const insuranceValueForType = (type: string): number => INSURANCE_VALUE_BY_TYPE[type] ?? 0;
32	
33	const DEDUCTIBLE = 100;
34	const CAP_MULTIPLIER = 2;
35	
36	const policyInsuranceSum = (items: Item[]): number =>
37	  sum(items.map((item) => insuranceValueForType(item.type)));
38	
39	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
40	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
41	
42	const reimbursableAmount = (damage: Damage, item: Item | undefined): number => {
43	  if (item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
44	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
45	  }
46	  return damage.amount;
47	};
48	
49	const damagePayout = (damage: Damage, item: Item | undefined): number =>
50	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
51	
52	const processClaim = (
53	  items: Item[],
54	  incident: Incident,
55	  remainingCap: number,
56	): { payout: number; remainingCap: number } => {
57	  const rawPayout = sum(
58	    incident.damages.map((damage) =>
59	      damagePayout(damage, items.find((item) => item.type === damage.itemType)),
60	    ),
61	  );
62	  const payout = Math.min(rawPayout, remainingCap);
63	  return { payout, remainingCap: remainingCap - payout };
64	};
65	
66	const basePremiumForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
67	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
68	
69	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
70	const BLOCK_SIZE = 3;
71	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
72	
73	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
74	
75	const componentGroupPremium = (type: string, count: number): number =>
76	  count === BLOCK_SIZE ? BLOCK_OF_THREE_BASE_PREMIUM : count * basePremiumForType(type);
77	
78	const groupByType = (items: Item[]): Map<string, number> => {
79	  const counts = new Map<string, number>();
80	  for (const item of items) {
81	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
82	  }
83	  return counts;
84	};
85	
86	const sum = (values: number[]): number => values.reduce((total, value) => total + value, 0);
87	
88	const policyBasePremium = (items: Item[]): number => {
89	  const mainItems = items.filter((item) => !isComponent(item));
90	  const componentItems = items.filter(isComponent);
91	  const componentCounts = groupByType(componentItems);
92	
93	  const mainTotal = sum(mainItems.map(itemBasePremium));
94	  const componentTotal = sum(
95	    [...componentCounts].map(([type, count]) => componentGroupPremium(type, count)),
96	  );
97	
98	  return mainTotal + componentTotal;
99	};
100	
101	const CURSE_SURCHARGE_RATE = 0.5;
102	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
103	const HIGH_ENCHANTMENT_THRESHOLD = 5;
104	
105	const itemSurcharges = (item: Item): number => {
106	  const base = itemBasePremium(item);
107	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
108	  const highEnch =
109	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
110	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
111	      : 0;
112	  return curse + highEnch;
113	};
114	
115	const LOYALTY_DISCOUNT_RATE = 0.2;
116	const LOYALTY_YEARS_THRESHOLD = 2;
117	const FOLLOWUP_DISCOUNT_RATE = 0.15;
118	
119	const perItemSurcharges = (items: Item[]): number => sum(items.map(itemSurcharges));
120	
121	const policyWideDiscounts = (
122	  basePremium: number,
123	  customer: Customer,
124	  isFollowUp: boolean,
125	): number => {
126	  const loyalty =
127	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
128	  const followUp = isFollowUp ? basePremium * FOLLOWUP_DISCOUNT_RATE : 0;
129	  return loyalty + followUp;
130	};
131	
132	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
133	  const basePremium = policyBasePremium(items);
134	  const surcharges = perItemSurcharges(items);
135	  const discounts = policyWideDiscounts(basePremium, customer, isFollowUp);
136	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
137	  const premiumBeforeFee = Math.ceil(basePremium + surcharges - discounts + firstInsurance);
138	  return premiumBeforeFee + PROCESSING_FEE;
139	};
140	
141	export const runScenario = (scenario: Scenario): unknown => {
142	  let quoteCount = 0;
143	  const policies: Item[][] = [];
144	  const remainingCaps: number[] = [];
145	  const results = scenario.steps.map((step) => {
146	    if (step.op === "quote") {
147	      const isFollowUp = quoteCount > 0;
148	      quoteCount += 1;
149	      policies.push(step.items);
150	      remainingCaps.push(policyInsuranceSum(step.items) * CAP_MULTIPLIER);
151	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
152	    }
153	    const result = processClaim(policies[step.policy], step.incident, remainingCaps[step.policy]);
154	    remainingCaps[step.policy] = result.remainingCap;
155	    return result;
156	  });
157	  return { results };
158	};
